"use client";

/**
 * PageHeader Component
 *
 * A page header for SaaS dashboards with breadcrumbs, title, description, and actions.
 * Optimized for Product Mode with minimal visual noise and clear hierarchy.
 *
 * @example
 * ```tsx
 * <PageHeader
 *   breadcrumbs={[
 *     { label: 'Dashboard', href: '/' },
 *     { label: 'Users' }
 *   ]}
 *   title="Users"
 *   description="Manage user accounts and permissions"
 *   actions={<Button>Add User</Button>}
 * />
 * ```
 */

import { forwardRef } from "react";
import { ChevronRight, ChevronLeft } from "lucide-react";
import type { PageHeaderProps } from "./PageHeader.types";
import styles from "./PageHeader.module.css";

export const PageHeader = forwardRef<HTMLDivElement, PageHeaderProps>(
  (
    {
      title,
      description,
      breadcrumbs,
      actions,
      tabs,
      activeTab,
      onTabChange,
      backLink,
      badge,
      variant = "default",
      size = "md",
      bordered = true,
      sticky = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const classNames = [
      styles.pageHeader,
      styles[`variant-${variant}`],
      styles[`size-${size}`],
      bordered && styles.bordered,
      sticky && styles.sticky,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    const handleTabClick = (tabId: string, href?: string) => {
      if (onTabChange) {
        onTabChange(tabId);
      }
      if (href) {
        window.location.href = href;
      }
    };

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Back link */}
        {backLink && (
          <div className={styles.backLink}>
            {backLink.href ? (
              <a href={backLink.href} className={styles.backLinkAnchor}>
                <ChevronLeft size={16} />
                <span>{backLink.label || "Back"}</span>
              </a>
            ) : (
              <button
                type="button"
                onClick={backLink.onClick}
                className={styles.backLinkButton}
              >
                <ChevronLeft size={16} />
                <span>{backLink.label || "Back"}</span>
              </button>
            )}
          </div>
        )}

        {/* Breadcrumbs */}
        {breadcrumbs && breadcrumbs.length > 0 && (
          <nav className={styles.breadcrumbs} aria-label="Breadcrumb">
            <ol className={styles.breadcrumbList}>
              {breadcrumbs.map((crumb, index) => (
                <li key={crumb.label} className={styles.breadcrumbItem}>
                  {index > 0 && (
                    <ChevronRight
                      size={14}
                      className={styles.breadcrumbSeparator}
                    />
                  )}
                  {crumb.href ? (
                    <a href={crumb.href} className={styles.breadcrumbLink}>
                      {crumb.label}
                    </a>
                  ) : crumb.onClick ? (
                    <button
                      type="button"
                      onClick={crumb.onClick}
                      className={styles.breadcrumbButton}
                    >
                      {crumb.label}
                    </button>
                  ) : (
                    <span
                      className={styles.breadcrumbCurrent}
                      aria-current="page"
                    >
                      {crumb.label}
                    </span>
                  )}
                </li>
              ))}
            </ol>
          </nav>
        )}

        {/* Main header row */}
        <div className={styles.main}>
          <div className={styles.titleSection}>
            <div className={styles.titleRow}>
              <h1 className={styles.title}>{title}</h1>
              {badge && <span className={styles.badge}>{badge}</span>}
            </div>
            {description && <p className={styles.description}>{description}</p>}
          </div>

          {actions && <div className={styles.actions}>{actions}</div>}
        </div>

        {/* Tabs */}
        {tabs && tabs.length > 0 && (
          <div className={styles.tabs} role="tablist">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                role="tab"
                type="button"
                aria-selected={activeTab === tab.id}
                className={`${styles.tab} ${activeTab === tab.id ? styles.tabActive : ""}`}
                onClick={() => handleTabClick(tab.id, tab.href)}
              >
                <span>{tab.label}</span>
                {tab.badge && (
                  <span className={styles.tabBadge}>{tab.badge}</span>
                )}
              </button>
            ))}
          </div>
        )}
      </div>
    );
  },
);

PageHeader.displayName = "PageHeader";

/**
 * PageHeader Component Types
 *
 * Type definitions for the Orion PageHeader section component.
 * Designed for Product Mode (SaaS dashboards) with breadcrumbs, actions, and tabs.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Breadcrumb item
 */
export interface BreadcrumbItem {
  /**
   * Display label
   */
  label: string;

  /**
   * Navigation URL (optional for current item)
   */
  href?: string;

  /**
   * Click handler (alternative to href)
   */
  onClick?: () => void;
}

/**
 * Tab item for page header navigation
 */
export interface PageHeaderTab {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Display label
   */
  label: string;

  /**
   * Optional badge/count
   */
  badge?: ReactNode;

  /**
   * Tab href for navigation
   */
  href?: string;
}

/**
 * PageHeader size variant
 */
export type PageHeaderSize = "sm" | "md" | "lg";

/**
 * PageHeader visual variant
 */
export type PageHeaderVariant =
  | "default"
  | "compact"
  | "with-tabs"
  | "transparent";

/**
 * PageHeader section props
 *
 * @example
 * ```tsx
 * <PageHeader
 *   breadcrumbs={[
 *     { label: 'Dashboard', href: '/' },
 *     { label: 'Users' }
 *   ]}
 *   title="Users"
 *   description="Manage user accounts and permissions"
 *   actions={<Button>Add User</Button>}
 * />
 * ```
 */
export interface PageHeaderProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "title"
> {
  /**
   * Page title
   */
  title: ReactNode;

  /**
   * Optional description below title
   */
  description?: ReactNode;

  /**
   * Breadcrumb navigation items
   */
  breadcrumbs?: BreadcrumbItem[];

  /**
   * Action buttons/elements aligned right
   */
  actions?: ReactNode;

  /**
   * Tab navigation items
   */
  tabs?: PageHeaderTab[];

  /**
   * Currently active tab ID
   */
  activeTab?: string;

  /**
   * Tab change handler
   */
  onTabChange?: (tabId: string) => void;

  /**
   * Back link for navigation
   */
  backLink?: {
    label?: string;
    href?: string;
    onClick?: () => void;
  };

  /**
   * Optional badge next to title
   */
  badge?: ReactNode;

  /**
   * Visual variant
   * - default: Standard layout with padding
   * - compact: Reduced spacing
   * - with-tabs: Includes tab navigation
   * @default 'default'
   */
  variant?: PageHeaderVariant;

  /**
   * Size variant
   * @default 'md'
   */
  size?: PageHeaderSize;

  /**
   * Show border at bottom
   * @default true
   */
  bordered?: boolean;

  /**
   * Sticky positioning
   * @default false
   */
  sticky?: boolean;
}

/**
 * PageHeader Component Styles
 *
 * Modern, elegant page header.
 * Uses mode-aware tokens for responsive styling.
 */

.pageHeader {
  display: flex;
  flex-direction: column;
  background: var(--surface-base);
  padding: var(--spacing-6) var(--mode-spacing-block);
}

.bordered {
  border-bottom: 1px solid var(--border-subtle);
}

.sticky {
  position: sticky;
  top: 0;
  z-index: var(--z-sticky);
}

/* ============================================================================
 * BACK LINK
 * ============================================================================ */

.backLink {
  margin-bottom: var(--spacing-2);
}

.backLinkAnchor,
.backLinkButton {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  text-decoration: none;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  transition: color var(--mode-hover-duration);
}

.backLinkAnchor:hover,
.backLinkButton:hover {
  color: var(--text-primary);
}

/* ============================================================================
 * BREADCRUMBS
 * ============================================================================ */

.breadcrumbs {
  margin-bottom: var(--spacing-3);
}

.breadcrumbList {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: var(--spacing-1);
}

.breadcrumbItem {
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
}

.breadcrumbSeparator {
  color: var(--text-tertiary);
  flex-shrink: 0;
}

.breadcrumbLink,
.breadcrumbButton {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  text-decoration: none;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  transition: color var(--mode-hover-duration);
}

.breadcrumbLink:hover,
.breadcrumbButton:hover {
  color: var(--text-primary);
}

.breadcrumbCurrent {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-tertiary);
}

/* ============================================================================
 * MAIN HEADER
 * ============================================================================ */

.main {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--mode-spacing-element);
  flex-wrap: wrap;
}

.titleSection {
  flex: 1;
  min-width: 0;
}

.titleRow {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  flex-wrap: wrap;
}

.title {
  font-family: var(--font-primary);
  font-size: var(--mode-text-title);
  font-weight: 600;
  line-height: var(--line-height-tight);
  color: var(--text-primary);
  margin: 0;
  letter-spacing: -0.02em;
}

.badge {
  flex-shrink: 0;
}

.description {
  font-family: var(--font-secondary);
  font-size: var(--mode-text-body);
  color: var(--text-secondary);
  line-height: var(--line-height-relaxed);
  margin: var(--spacing-1) 0 0 0;
  max-width: 600px;
}

/* ============================================================================
 * ACTIONS
 * ============================================================================ */

.actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  flex-shrink: 0;
  flex-wrap: wrap;
}

/* ============================================================================
 * TABS
 * ============================================================================ */

.tabs {
  display: flex;
  gap: 0;
  margin-top: var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
  margin-bottom: calc(var(--mode-spacing-element) * -1);
  margin-left: calc(var(--mode-spacing-block) * -1);
  margin-right: calc(var(--mode-spacing-block) * -1);
  padding-left: var(--mode-spacing-block);
  padding-right: var(--mode-spacing-block);
}

.tab {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: none;
  border: none;
  padding: var(--spacing-3) var(--spacing-4);
  cursor: pointer;
  border-bottom: 2px solid transparent;
  margin-bottom: -1px;
  transition:
    color var(--mode-hover-duration),
    border-color var(--mode-hover-duration);
}

.tab:hover {
  color: var(--text-primary);
}

.tabActive {
  color: var(--interactive-primary);
  border-bottom-color: var(--interactive-primary);
}

.tabBadge {
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  color: var(--text-tertiary);
  background: var(--surface-subtle);
  padding: var(--spacing-0-5) var(--spacing-2);
  border-radius: var(--radius-full);
}

.tabActive .tabBadge {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

/* ============================================================================
 * SIZE VARIANTS
 * ============================================================================ */

.size-sm {
  padding: var(--spacing-3) var(--spacing-4);
}

.size-sm .title {
  font-size: var(--font-size-18);
}

.size-sm .description {
  font-size: var(--font-size-13);
}

.size-lg {
  padding: var(--spacing-8) var(--spacing-8);
}

.size-lg .title {
  font-size: var(--font-size-32);
}

/* ============================================================================
 * VARIANT: COMPACT
 * ============================================================================ */

.variant-compact {
  padding: var(--spacing-3) var(--spacing-4);
}

.variant-compact .main {
  gap: var(--spacing-4);
}

.variant-compact .title {
  font-size: var(--font-size-16);
}

.variant-compact .description {
  font-size: var(--font-size-12);
  margin-top: 0;
}

.variant-compact .breadcrumbs {
  margin-bottom: var(--spacing-2);
}

/* ============================================================================
 * VARIANT: WITH-TABS
 * ============================================================================ */

.variant-with-tabs {
  padding-bottom: 0;
}

/* ============================================================================
 * VARIANT: TRANSPARENT (Minimal Product UI)
 * ============================================================================ */

.variant-transparent {
  background: transparent;
  border-bottom: none;
  padding: 0 var(--spacing-6);
  padding-top: var(--spacing-6);
  padding-bottom: 0;
}

.variant-transparent.bordered {
  border-bottom: none;
}

/* Tabs in transparent variant - clean, no background */
.variant-transparent .tabs {
  margin-left: 0;
  margin-right: 0;
  padding-left: 0;
  padding-right: 0;
  margin-top: var(--spacing-4);
  margin-bottom: 0;
  border-bottom: 1px solid var(--border-subtle);
}

.variant-transparent .tab:first-child {
  padding-left: 0;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 768px) {
  .pageHeader {
    padding: var(--spacing-4);
  }

  .main {
    flex-direction: column;
    align-items: stretch;
    gap: var(--spacing-4);
  }

  .actions {
    width: 100%;
    justify-content: flex-start;
  }

  /* Transparent variant keeps actions inline on mobile (product/compact UI) */
  .variant-transparent .main {
    flex-direction: row;
    align-items: center;
  }

  .variant-transparent .actions {
    width: auto;
    flex-shrink: 0;
  }

  .tabs {
    margin-left: -var(--spacing-4);
    margin-right: -var(--spacing-4);
    padding-left: var(--spacing-4);
    padding-right: var(--spacing-4);
    overflow-x: auto;
  }

  .tab {
    white-space: nowrap;
  }
}

export { PageHeader } from "./PageHeader";
export type {
  PageHeaderProps,
  PageHeaderVariant,
  PageHeaderSize,
  BreadcrumbItem,
  PageHeaderTab,
} from "./PageHeader.types";
